use serde_json::{json, Value};
fn execute(input: &Value) -> Value {
    let items: Vec<String> = input["items"]
        .as_array()
        .map(|a| a.iter().filter_map(|v| v.as_str().map(|s| s.to_string())).collect())
        .unwrap_or_default();
    let new_item = input["new_item"].as_str().unwrap_or("");

    let item_nodes: Vec<Value> = items.iter().enumerate().map(|(i, text)| {
        json!({
            "tag": "li",
            "props": { "class": "todo-item" },
            "children": [
                { "$text": text },
                {
                    "tag": "button",
                    "props": {
                        "class": "btn btn-del",
                        "onClick": { "$event": "remove", "$index": i }
                    },
                    "children": [{ "$text": "✕" }]
                }
            ]
        })
    }).collect();

    let empty_msg: Vec<Value> = if items.is_empty() {
        vec![json!({ "tag": "li", "props": { "class": "todo-empty" }, "children": [{ "$text": "No items yet. Add one above!" }] })]
    } else {
        vec![]
    };
    let mut all_items = item_nodes;
    all_items.extend(empty_msg);

    json!({
        "tag": "div",
        "props": { "class": "todo-app" },
        "children": [
            { "tag": "h1", "props": { "class": "todo-title" }, "children": [{ "$text": "Todo" }] },
            {
                "tag": "div",
                "props": { "class": "todo-add" },
                "children": [
                    {
                        "tag": "input",
                        "props": {
                            "class": "todo-input",
                            "type": "text",
                            "placeholder": "New item…",
                            "value": new_item,
                            "onInput": { "$event": "set", "$target": "new_item" }
                        },
                        "children": []
                    },
                    {
                        "tag": "button",
                        "props": {
                            "class": "btn btn-add",
                            "onClick": { "$event": "add" }
                        },
                        "children": [{ "$text": "Add" }]
                    }
                ]
            },
            { "tag": "ul", "props": { "class": "todo-list" }, "children": all_items }
        ]
    })
}
